// Extrai dados da mensagem recebida via Evolution API webhook
const body = $input.first().json.body || $input.first().json;

// Evolution API envia assim:
const data    = body.data || body;
const msgText = data?.message?.conversation 
             || data?.message?.extendedTextMessage?.text 
             || '';
const from    = (data?.key?.remoteJid || '').replace('@s.whatsapp.net', '').replace(/\D/g, '');

if (!msgText || !from) return [];

// Detecta se é uma lista de figurinhas
// Aceita formatos: BRA1, BRA 1, BRA-1 — um por linha ou separado por vírgula
const lines = msgText
  .toUpperCase()
  .split(/[\n,;]+/)
  .map(l => l.trim().replace(/\s+/, ''))
  .filter(l => /^[A-Z]{2,3}\d{1,2}$|^FWC\d{1,2}$|^00$/.test(l));

if (lines.length === 0) return []; // não é lista de figurinhas

return [{ json: { from, codes: lines, raw: msgText } }];

const input    = $input.first().json;
const from     = $('Extrai lista de códigos').first().json.from;
const codes    = $('Extrai lista de códigos').first().json.codes;
const estoque  = Array.isArray(input) ? input : [];

// Preço por código
function preco(code) {
  if (!code) return 1;
  if (code === '00' || code.startsWith('FWC')) return 2;
  if (/^[A-Z]{2,3}1$/.test(code)) return 2;
  return 1;
}

// Desconto por volume
function precoDesconto(code, total) {
  const base = preco(code);
  const spec = base === 2;
  if (total >= 500) return spec ? 1.85 : 0.85;
  if (total >= 250) return spec ? 1.90 : 0.90;
  if (total >= 150) return spec ? 1.95 : 0.95;
  return base;
}

const estoqueMap = new Map(estoque.map(s => [s.code, s]));

const disponiveis = [];
const indisponiveis = [];

for (const code of codes) {
  const s = estoqueMap.get(code);
  if (s && s.quantity > 0) {
    disponiveis.push({ code, qty: s.quantity, name: s.name });
  } else {
    indisponiveis.push(code);
  }
}

const totalQty = disponiveis.length; // 1 de cada pedida

// Monta resposta
const linhasDisp = disponiveis.map(s => {
  const p = precoDesconto(s.code, totalQty);
  return `  ✅ ${s.code} — ${brl(p)}`;
});

const linhasIndisp = indisponiveis.map(c => `  ❌ ${c}`);

const totalValor = disponiveis.reduce((acc, s) => acc + precoDesconto(s.code, totalQty), 0);

function brl(v) {
  return 'R$ ' + v.toFixed(2).replace('.', ',');
}

let descMsg = '';
if (totalQty >= 500) descMsg = '\n🏷️ _Desconto de 15% aplicado (500+ figurinhas)_';
else if (totalQty >= 250) descMsg = '\n🏷️ _Desconto de 10% aplicado (250+ figurinhas)_';
else if (totalQty >= 150) descMsg = '\n🏷️ _Desconto de 5% aplicado (150+ figurinhas)_';
else if (totalQty >= 100) descMsg = `\n💡 _Com 150+ figurinhas você ganha 5% de desconto_`;

let msg = '🔍 *Verificação de estoque*\n\n';

if (disponiveis.length > 0) {
  msg += `*Disponíveis (${disponiveis.length}):*\n`;
  msg += linhasDisp.join('\n') + '\n';
  msg += `\n💰 *Total: ${brl(totalValor)}*${descMsg}\n`;
}

if (indisponiveis.length > 0) {
  msg += `\n*Indisponíveis (${indisponiveis.length}):*\n`;
  msg += linhasIndisp.join('\n') + '\n';
}

if (disponiveis.length > 0) {
  msg += `\n_Para comprar, acesse o catálogo ou responda confirmando!_ 🛒`;
}

return [{ json: { from, msg, totalValor, qtdDisp: disponiveis.length } }];
